class MyClass {
private:
 int data;
 static int allocationCount;
public:
 MyClass() : data(0) {}
 MyClass(int d) : data(d) {}

 // Overload new operator
 static void* operator new(size_t size) {
 allocationCount++;
 std::cout << "Custom new: Allocating " << size << " bytes\n";
 return ::operator new(size); // Call global new
 }

 // Overload delete operator
 static void operator delete(void* ptr) noexcept {
 allocationCount--;
 std::cout << "Custom delete: Deallocating memory\n";
 ::operator delete(ptr); // Call global delete
 }

 static int getAllocationCount() { return allocationCount; }
};

int MyClass::allocationCount = 0;

int main() {
 MyClass* obj1 = new MyClass(10);
 MyClass* obj2 = new MyClass(20);

 delete obj1;
 delete obj2;

 std::cout << "Allocations: " << MyClass::getAllocationCount();
 return 0;
}

#include <iostream>
#include <new>

class Buffer {
private:
 int size;
public:
 Buffer(int s) : size(s) {
 std::cout << "Buffer constructed with size: " << size << "\n";
 }
 ~Buffer() {
 std::cout << "Buffer destroyed\n";
 }
 void process() { std::cout << "Processing buffer of size: " << size << "\n"; }
};

int main() {
 // Pre-allocate raw memory
 constexpr size_t bufferSize = sizeof(Buffer);
 char* rawMemory = new char[bufferSize];

 std::cout << "Memory allocated at: " << (void*)rawMemory << "\n";

 // Use placement new to construct object at that location
 Buffer* buf = new (rawMemory) Buffer(100);

 buf->process();

 // Explicitly call destructor (don't delete - memory not from new)
 buf->~Buffer();

 // Free the raw memory
 delete[] rawMemory;

 return 0;
}

#include <iostream>
#include <memory>
#include <vector>

class ObjectPool {
private:
 std::vector<char*> freeList;
 size_t objectSize;

public:
 ObjectPool(size_t size, size_t count) : objectSize(size) {
 // Pre-allocate pool
 for (size_t i = 0; i < count; ++i) {
 freeList.push_back(new char[objectSize]);
 }
 std::cout << "Pool created with " << count << " objects\n";
 }

 void* allocate() {
 if (freeList.empty()) {
 throw std::bad_alloc();
 }
 char* ptr = freeList.back();
 freeList.pop_back();
 std::cout << "Allocated from pool\n";
 return ptr;
 }

 void deallocate(void* ptr) {
 freeList.push_back(static_cast<char*>(ptr));
 std::cout << "Returned to pool\n";
 }

 ~ObjectPool() {
 for (auto* p : freeList) {
 delete[] p;
 }
 }
};

class MyData {
public:
 int value;
 MyData(int v = 0) : value(v) {}
};

int main() {
 ObjectPool pool(sizeof(MyData), 5);

 MyData* d1 = static_cast<MyData*>(pool.allocate());
 new (d1) MyData(42); // Placement new to construct
 std::cout << "Value: " << d1->value << "\n";

 d1->~MyData(); // Destruct
 pool.deallocate(d1); // Return to pool

 return 0;
}

#include <iostream>
#include <memory>

class Resource {
public:
 Resource() { std::cout << "Resource acquired\n"; }
 ~Resource() { std::cout << "Resource released\n"; }
 void use() { std::cout << "Resource in use\n"; }
};

int main() {
 // Using unique_ptr - exclusive ownership
 {
 std::unique_ptr<Resource> res1 = std::make_unique<Resource>();
 res1->use();
 // Automatically deleted when res1 goes out of scope
 }

 std::cout << "---\n";

 // Using shared_ptr - shared ownership
 {
 std::shared_ptr<Resource> res2 = std::make_shared<Resource>();
 std::shared_ptr<Resource> res2_copy = res2;

 std::cout << "Use count: " << res2.use_count() << "\n";
 // Deleted when last shared_ptr is destroyed
 }

 return 0;
}

#include <iostream>
#include <cstdlib>
#include <new>

// Track allocations
struct AllocInfo {
 void* ptr;
 size_t size;
 const char* file;
 int line;
};

// Simple tracking (for demonstration)
static size_t totalAllocated = 0;
static size_t totalFreed = 0;

// Overload global new
void* operator new(size_t size, const char* file, int line) {
 totalAllocated += size;
 void* ptr = std::malloc(size);
 if (!ptr) throw std::bad_alloc();
 std::cout << "NEW: " << size << " bytes at " << ptr 
 << " from " << file << ":" << line << "\n";
 return ptr;
}

// Overload global delete
void operator delete(void* ptr) noexcept {
 if (ptr) {
 std::cout << "DELETE: freeing " << ptr << "\n";
 std::free(ptr);
 }
}

// Macros to track file/line
